import { getSessionLogConsent, setSessionLogConsent } from "../config.js";
/**
 * Parse `sessionLogConsent` CLI args into an action.
 *
 * - no args / `get` -> read the current consent state
 * - `set true` / `set false` -> persist the consent state
 */
export function parseSessionLogConsentArgs(args) {
    const [verb, rawValue] = args;
    if (verb === undefined || verb === "get") {
        return { kind: "get" };
    }
    if (verb === "set") {
        if (rawValue === "true") {
            return { kind: "set", value: true };
        }
        if (rawValue === "false") {
            return { kind: "set", value: false };
        }
        throw new Error(`Expected "set true" or "set false", got "set ${rawValue ?? ""}".`);
    }
    throw new Error(`Unknown session-log-consent command "${verb}".`);
}
/**
 * Read or write the global session-log consent flag without spawning a fresh
 * `node -e` one-liner per call. `get` prints `true`, `false`, or `null` (one
 * token the agent can branch on); `set` persists the choice and confirms.
 */
export function runSessionLogConsent(args) {
    const action = parseSessionLogConsentArgs(args);
    if (action.kind === "get") {
        console.log(getSessionLogConsent() ?? "null");
        return;
    }
    setSessionLogConsent(action.value);
    console.log(action.value
        ? "Session log collection enabled."
        : "Session log collection disabled.");
}
